# dual explorer-H1 · S10-T3-A-E2
def bump(ver, kind):
    maj, mi, pa = map(int, ver.split("."))
    if kind == "major":
        return f"{maj+1}.0.0"
    if kind == "minor":
        return f"{maj}.{mi+1}.0"
    return f"{maj}.{mi}.{pa+1}"
print(bump("0.1.0", "minor"), bump("0.1.0", "patch"))

